import { motion, AnimatePresence } from 'framer-motion';
import { useState } from 'react';
import { User, Shield, Code, Cpu } from 'lucide-react';

interface TeamMember {
  id: string;
  name: string | JSX.Element;
  role: string;
  bio: string;
  icon: any;
  x: number;
  y: number;
  color: string;
}

const team: TeamMember[] = [
  {
    id: 'founder',
    name: 'Annem Akhila',
    role: 'Founder & CEO',
    bio: 'Visionary leader dedicated to bridging the gap between academia and industry through innovative technology education.',
    icon: Shield,
    x: 50,
    y: 40,
    color: 'hsl(var(--cosmic-orange))',
  },
  {
    id: 'tech-lead',
    name: 'Tech Architect',
    role: 'CTO',
    bio: 'Specialist in AI and large-scale system architecture, ensuring our solutions are built on the most robust technologies.',
    icon: Code,
    x: 30,
    y: 60,
    color: 'hsl(var(--electric-blue))',
  },
      {
        id: 'ops-lead',
        name: (
          <>
            MATURI JASWANTH SAI<br />
            MADHU MOHAN
          </>
        ),
        role: 'Operations Head',
      bio: 'Expert in project management and operational efficiency, driving the successful delivery of our global projects.',
      icon: Cpu,
      x: 70,
      y: 65,
      color: 'hsl(var(--starlight))',
    },
];

export const CelestialTeamMap = () => {
  const [selected, setSelected] = useState<TeamMember | null>(null);

  return (
    <div className="relative w-full h-[300px] md:h-[400px] bg-muted/10 rounded-2xl md:rounded-3xl border border-border/30 overflow-hidden group">
      {/* Background Star Lines (Constellation) */}
      <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-20">
        <line x1="50%" y1="40%" x2="30%" y2="60%" stroke="white" strokeWidth="1" strokeDasharray="4 4" />
        <line x1="50%" y1="40%" x2="70%" y2="65%" stroke="white" strokeWidth="1" strokeDasharray="4 4" />
      </svg>

      {team.map((member) => (
        <motion.div
          key={member.id}
          className="absolute cursor-pointer z-10"
          style={{ left: `${member.x}%`, top: `${member.y}%` }}
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          whileHover={{ scale: 1.2 }}
          onClick={() => setSelected(member)}
        >
          <div className="relative -translate-x-1/2 -translate-y-1/2">
            {/* Planet Glow */}
            <motion.div
              className="absolute inset-0 rounded-full blur-md"
              style={{ backgroundColor: member.color }}
              animate={{ opacity: [0.4, 0.8, 0.4] }}
              transition={{ duration: 3, repeat: Infinity }}
            />
            {/* Planet Body */}
            <div 
              className="relative w-8 h-8 md:w-12 md:h-12 rounded-full border-2 border-white/20 flex items-center justify-center bg-background shadow-lg"
              style={{ borderColor: member.color }}
            >
              <member.icon className="w-4 h-4 md:w-6 md:h-6" style={{ color: member.color }} />
            </div>
            
            {/* Label */}
            <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 whitespace-nowrap text-[8px] md:text-[10px] font-display font-bold tracking-widest uppercase text-muted-foreground opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity">
              {member.name}
            </div>
          </div>
        </motion.div>
      ))}

      {/* Info Card Overlay */}
      <AnimatePresence>
        {selected && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            className="absolute bottom-2 left-2 right-2 md:bottom-6 md:left-6 md:right-6 p-4 md:p-6 space-card border-electric-blue/30 z-20"
          >
            <button 
              onClick={() => setSelected(null)}
              className="absolute top-2 right-2 md:top-4 md:right-4 text-muted-foreground hover:text-foreground p-1"
            >
              ✕
            </button>
            <div className="flex items-center gap-3 md:gap-4 mb-2 md:mb-3">
              <div 
                className="w-8 h-8 md:w-10 md:h-10 rounded-full flex items-center justify-center border border-white/10"
                style={{ backgroundColor: `${selected.color}22` }}
              >
                <selected.icon className="w-4 h-4 md:w-5 md:h-5" style={{ color: selected.color }} />
              </div>
              <div>
                <h4 className="font-display font-bold text-base md:text-lg leading-none">{selected.name}</h4>
                <p className="text-[10px] md:text-xs text-electric-blue uppercase tracking-widest mt-1">{selected.role}</p>
              </div>
            </div>
            <p className="text-xs md:text-sm text-muted-foreground leading-relaxed">
              {selected.bio}
            </p>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="absolute top-2 left-4 md:top-4 md:left-6 text-[8px] md:text-[10px] font-display tracking-[0.2em] text-muted-foreground/50 uppercase">
        Explore our team
      </div>
    </div>
  );
};

import { motion, useScroll, useTransform, useSpring } from 'framer-motion';
import { useMemo, useRef, useState, useEffect } from 'react';

export function PlanetaryHeroBackground() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [isMobile, setIsMobile] = useState(false);
  const { scrollY } = useScroll();
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(window.innerWidth < 768 || 'ontouchstart' in window);
    };
    checkMobile();
    window.addEventListener('resize', checkMobile);

    const handleMouseMove = (e: MouseEvent) => {
      if (window.innerWidth < 768) return;
      // Normalize mouse position to range [-1, 1]
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 2,
        y: (e.clientY / window.innerHeight - 0.5) * 2,
      });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => {
      window.removeEventListener('resize', checkMobile);
      window.removeEventListener('mousemove', handleMouseMove);
    };
  }, []);

  const smoothMouseX = useSpring(0, { stiffness: 50, damping: 25 });
  const smoothMouseY = useSpring(0, { stiffness: 50, damping: 25 });

  useEffect(() => {
    if (!isMobile) {
      smoothMouseX.set(mousePosition.x);
      smoothMouseY.set(mousePosition.y);
    }
  }, [mousePosition.x, mousePosition.y, smoothMouseX, smoothMouseY, isMobile]);

  // Parallax and Perspective transforms
  const parallaxYBase = useTransform(scrollY, [0, 1000], [0, isMobile ? -100 : -200]);
  const rotateX = useTransform(smoothMouseY, [-1, 1], [2, -2]); // Vertical tilt
  const rotateY = useTransform(smoothMouseX, [-1, 1], [-2, 2]); // Horizontal tilt
  
    // Multiple layers for deep 3D effect
    const starsCount = isMobile ? 15 : 100;
    const stars = useMemo(() => [...Array(starsCount)].map((_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 100,
      size: Math.random() * 1.5 + 0.5,
      duration: 3 + Math.random() * 5,
      delay: Math.random() * 5,
      opacity: Math.random() * 0.5 + 0.2,
    })), [isMobile, starsCount]);
  
    const groundEnergyCount = isMobile ? 2 : 15;
    const groundEnergy = useMemo(() => [...Array(groundEnergyCount)].map((_, i) => ({
      id: i,
      left: `${Math.random() * 100}%`,
      bottom: `${Math.random() * 40}%`,
      width: `${Math.random() * (isMobile ? 80 : 150) + 50}px`,
      height: `${Math.random() * 3 + 1}px`,
      delay: Math.random() * 4,
      duration: 2 + Math.random() * 3,
    })), [isMobile, groundEnergyCount]);


  const bgImage = "https://slelguoygbfzlpylpxfs.supabase.co/storage/v1/render/image/public/document-uploads/Screenshot-2025-12-27-133742-1766822869625.png";

  return (
    <div 
      ref={containerRef}
      className="fixed inset-0 overflow-hidden pointer-events-none z-0 bg-[#020008]"
      style={{ perspective: isMobile ? 'none' : '1200px' }}
    >
      {/* 3D Wrapper Layer */}
      <motion.div 
        style={{ 
          y: parallaxYBase,
          rotateX: isMobile ? 0 : rotateX,
          rotateY: isMobile ? 0 : rotateY,
          transformStyle: isMobile ? 'flat' : 'preserve-3d'
        }}
        className={`absolute inset-0 ${isMobile ? '' : 'inset-[-15%]'} z-0`}
      >
        {/* Main Image Layer (Base) */}
        <div 
          className="absolute inset-0 bg-cover bg-center bg-no-repeat opacity-95 scale-110"
          style={{ 
            backgroundImage: `url(${bgImage})`,
            transform: isMobile ? 'none' : 'translateZ(-50px)' 
          }}
        />

        {/* Space Enhancement: Dynamic Star Field (Upper Layer) */}
        <div className="absolute inset-0 z-10" style={{ transform: isMobile ? 'none' : 'translateZ(20px)' }}>
          {stars.map((star) => (
            <motion.div
              key={star.id}
              className="absolute bg-white rounded-full"
              style={{
                left: `${star.x}%`,
                top: `${star.y}%`,
                width: star.size,
                height: star.size,
                opacity: star.opacity,
                boxShadow: `0 0 ${star.size * 3}px rgba(255, 255, 255, 0.8)`,
              }}
              animate={{
                opacity: [star.opacity, star.opacity * 0.3, star.opacity],
                scale: [1, 1.2, 1],
              }}
              transition={{
                duration: star.duration,
                repeat: Infinity,
                ease: "easeInOut",
                delay: star.delay,
              }}
            />
          ))}
        </div>

        {/* Ground Enhancement: Energy Veins (Isolated to bottom 40%) */}
        <div className="absolute inset-0 z-20 overflow-hidden" style={{ transform: isMobile ? 'none' : 'translateZ(100px)' }}>
          {groundEnergy.map((vein) => (
            <motion.div
              key={vein.id}
              className="absolute rounded-full"
              style={{
                left: vein.left,
                bottom: vein.bottom,
                width: vein.width,
                height: vein.height,
                background: 'linear-gradient(90deg, transparent, rgba(249, 115, 22, 0.4), rgba(251, 191, 36, 0.6), rgba(249, 115, 22, 0.4), transparent)',
                filter: 'blur(3px)',
              }}
              animate={{
                opacity: [0.1, 0.5, 0.1],
                scaleX: [0.8, 1.2, 0.8],
                x: [-10, 10, -10],
              }}
              transition={{
                duration: vein.duration,
                repeat: Infinity,
                ease: "easeInOut",
                delay: vein.delay,
              }}
            />
          ))}
        </div>

        {/* Cinematic Nebula Glows - REDUCED ON MOBILE */}
        <div className="absolute inset-0 z-15 mix-blend-screen" style={{ transform: isMobile ? 'none' : 'translateZ(40px)' }}>
          {/* Top Right Nova Glow */}
          {!isMobile && (
            <motion.div
              className="absolute right-[10%] top-[35%] w-[600px] h-[600px] rounded-full"
              style={{
                background: 'radial-gradient(circle, rgba(147, 51, 234, 0.15) 0%, transparent 70%)',
                filter: 'blur(60px)',
              }}
              animate={{ opacity: [0.3, 0.6, 0.3], scale: [1, 1.1, 1] }}
              transition={{ duration: 8, repeat: Infinity, ease: "easeInOut" }}
            />
          )}
          {/* Bottom Magma Glow */}
          <motion.div
            className={`absolute bottom-[-10%] left-[20%] ${isMobile ? 'w-[300px] h-[150px]' : 'w-[1000px] h-[400px]'} rounded-full`}
            style={{
              background: 'radial-gradient(ellipse, rgba(249, 115, 22, 0.2) 0%, transparent 80%)',
              filter: isMobile ? 'blur(30px)' : 'blur(50px)',
            }}
            animate={{ opacity: [0.4, 0.7, 0.4] }}
            transition={{ duration: 5, repeat: Infinity, ease: "easeInOut" }}
          />
        </div>
      </motion.div>

      {/* Static Overlays (Not affected by 3D tilt for stability) */}
      
      {/* Ground Heat Shimmer SVG Filter Overlay - DISABLED ON MOBILE */}
      {!isMobile && (
        <>
          <svg className="hidden">
            <filter id="heat-shimmer">
              <feTurbulence type="fractalNoise" baseFrequency="0.01 0.05" numOctaves="2" seed="1">
                <animate attributeName="seed" from="1" to="100" dur="10s" repeatCount="indefinite" />
              </feTurbulence>
              <feDisplacementMap in="SourceGraphic" scale="5" />
            </filter>
          </svg>
          
          <div 
            className="absolute bottom-0 left-0 w-full h-[45%] z-25 pointer-events-none opacity-40"
            style={{ filter: 'url(#heat-shimmer)' }}
          >
            <div className="w-full h-full bg-transparent" />
          </div>
        </>
      )}

      {/* Atmospheric Fog/Mist (Foreground) */}
      <div className="absolute inset-0 z-30 pointer-events-none">
        <div className="absolute bottom-0 left-0 w-full h-[40%] bg-gradient-to-t from-[#020008] via-transparent to-transparent opacity-80" />
        <div className="absolute inset-0 bg-gradient-to-b from-[#020008]/40 via-transparent to-transparent opacity-60" />
      </div>

      {/* Vignette & Color Grading */}
      <div className="absolute inset-0 z-40 pointer-events-none">
        <div className="absolute inset-0 shadow-[inset_0_0_200px_rgba(0,0,0,0.9)]" />
        <div className="absolute inset-0 bg-[#020008]/10 mix-blend-multiply" />
      </div>
    </div>
  );
}

export default PlanetaryHeroBackground;

import { useState, useEffect, useRef } from 'react';
import { Volume2, VolumeX } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

  export const SpaceAudio = ({ showControls = true }: { showControls?: boolean }) => {
    const [isPlaying, setIsPlaying] = useState(true);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const hasInteracted = useRef(false);

    const toggleAudio = (e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      if (audioRef.current) {
        if (isPlaying) {
          audioRef.current.pause();
          setIsPlaying(false);
        } else {
          audioRef.current.play().catch(err => {
            console.error("Audio playback failed:", err);
            setIsPlaying(false);
          });
          setIsPlaying(true);
        }
      }
    };

    useEffect(() => {
    if ('mediaSession' in navigator) {
      navigator.mediaSession.metadata = new MediaMetadata({
        title: 'Cornfield Chase (Cosmic Theme)',
        artist: 'Afferent Technologies Pvt Ltd',
        album: 'Cosmic Navigator',
        artwork: [
          { src: '/logo.svg', sizes: '512x512', type: 'image/svg+xml' }
        ]
      });

      navigator.mediaSession.setActionHandler('play', () => {
        if (audioRef.current) {
          audioRef.current.play();
          setIsPlaying(true);
        }
      });
      navigator.mediaSession.setActionHandler('pause', () => {
        if (audioRef.current) {
          audioRef.current.pause();
          setIsPlaying(false);
        }
      });
    }
  }, []);

  const handleAudioError = (e: any) => {
      console.error("Audio source failed to load:", e);
      setIsPlaying(false);
    };

    useEffect(() => {
      const attemptPlay = () => {
        if (audioRef.current && !hasInteracted.current) {
          audioRef.current.play()
            .then(() => {
              setIsPlaying(true);
              hasInteracted.current = true;
              window.removeEventListener('click', attemptPlay);
              window.removeEventListener('keydown', attemptPlay);
              window.removeEventListener('touchstart', attemptPlay);
            })
            .catch(() => {
              // Auto-play failed, wait for user interaction
              setIsPlaying(false);
            });
        }
      };

      // Try playing immediately
      attemptPlay();

      // Add listeners for interaction to trigger play if autoplay was blocked
      window.addEventListener('click', attemptPlay);
      window.addEventListener('keydown', attemptPlay);
      window.addEventListener('touchstart', attemptPlay);

      // Cleanup on unmount
      return () => {
        window.removeEventListener('click', attemptPlay);
        window.removeEventListener('keydown', attemptPlay);
        window.removeEventListener('touchstart', attemptPlay);
        if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current = null;
        }
      };
    }, []);

    return (
      <div className="fixed bottom-8 left-8 z-[100]">
        <audio
          ref={audioRef}
          src="/cornfield-chase.mp3"
          loop
          preload="auto"
          onError={handleAudioError}
        />
        
        <AnimatePresence>
          {showControls && (
            <motion.button
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              onClick={toggleAudio}
              className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-500 shadow-lg ${
                isPlaying 
                  ? 'bg-electric-blue text-background shadow-electric-blue/40' 
                  : 'bg-muted/20 text-muted-foreground border border-border/30 backdrop-blur-md'
              }`}
            >
              <AnimatePresence mode="wait">
                {isPlaying ? (
                  <motion.div
                    key="volume-on"
                    initial={{ opacity: 0, scale: 0.5 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.5 }}
                  >
                    <Volume2 className="w-5 h-5" />
                  </motion.div>
                ) : (
                  <motion.div
                    key="volume-off"
                    initial={{ opacity: 0, scale: 0.5 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.5 }}
                  >
                    <VolumeX className="w-5 h-5" />
                  </motion.div>
                )}
              </AnimatePresence>
              
              {/* Animated pulse when playing */}
              {isPlaying && (
                <motion.div 
                  className="absolute inset-0 rounded-full border border-electric-blue"
                  animate={{ scale: [1, 1.5], opacity: [0.5, 0] }}
                  transition={{ duration: 2, repeat: Infinity }}
                />
              )}
            </motion.button>
          )}
        </AnimatePresence>
        
        <div className="absolute left-16 top-1/2 -translate-y-1/2 whitespace-nowrap pointer-events-none overflow-hidden">
          <AnimatePresence>
            {showControls && isPlaying && (
              <motion.span 
                initial={{ x: -20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                exit={{ x: -20, opacity: 0 }}
                className="text-[10px] font-display font-bold tracking-[0.2em] text-electric-blue uppercase bg-background/80 backdrop-blur-sm px-3 py-1 rounded-full border border-electric-blue/20"
              >
                Cornfield Chase
              </motion.span>
            )}
          </AnimatePresence>
        </div>
      </div>
    );

};

import { motion, useScroll, useTransform } from 'framer-motion';
import { useMemo, useRef, useState, useEffect } from 'react';

interface StarFieldProps {
  count?: number;
}

const StarItem = ({ size, left, top, color, opacity, duration, delay, isPulsating, isGiant, hasRays }: any) => {
  const isMobile = typeof window !== 'undefined' && window.innerWidth < 768;
  
  return (
    <motion.div
      className="absolute"
      style={{
        width: size + 'px',
        height: size + 'px',
        left,
        top,
        willChange: 'transform, opacity',
      }}
      animate={{
        opacity: [opacity, opacity * 0.4, opacity],
        scale: isPulsating ? [1, 1.2, 1] : [1, 1.05, 1],
      }}
      transition={{
        duration,
        repeat: Infinity,
        delay,
        ease: "easeInOut",
      }}
    >
      <div 
        className="absolute inset-0 rounded-full"
        style={{
          background: `radial-gradient(circle, white 0%, ${color} 50%, transparent 100%)`,
          boxShadow: isGiant && !isMobile
            ? `0 0 ${size * 2}px ${color}, 0 0 ${size * 4}px ${color}50`
            : isGiant ? `0 0 ${size}px ${color}` : 'none',
        }}
      />
      {hasRays && !isMobile && (
        <>
          <div 
            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2"
            style={{
              width: size * 6,
              height: 1,
              background: `linear-gradient(90deg, transparent, ${color}80, white, ${color}80, transparent)`,
            }}
          />
          <div 
            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2"
            style={{
              width: 1,
              height: size * 6,
              background: `linear-gradient(180deg, transparent, ${color}80, white, ${color}80, transparent)`,
            }}
          />
        </>
      )}
    </motion.div>
  );
};

const StarField = ({ count = 300 }: StarFieldProps) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollY } = useScroll();
  const [mounted, setMounted] = useState(false);
  const [isMobile, setIsMobile] = useState(false);
  
  useEffect(() => {
    setMounted(true);
    setIsMobile(window.innerWidth < 768);
  }, []);

  const layer1Y = useTransform(scrollY, [0, 2000], [0, -80]);
  const layer2Y = useTransform(scrollY, [0, 2000], [0, -160]);
  const layer3Y = useTransform(scrollY, [0, 2000], [0, -240]);
  const layer4Y = useTransform(scrollY, [0, 2000], [0, -40]);

  const [starLayers, setStarLayers] = useState<any[][]>([[], [], [], []]);
  const [cosmicDust, setCosmicDust] = useState<any[]>([]);
  const [starClusters, setStarClusters] = useState<any[]>([]);

    useEffect(() => {
      const mobile = window.innerWidth < 768;
      const finalCount = mobile ? Math.min(count, 40) : count;
      
      const layers: any[][] = [[], [], [], []];
      const starColors = [
        '#ffffff', '#fff8f0', '#ffeedd', '#aaccff', '#88bbff',
        '#ffddaa', '#ff9966', '#aaffff', '#ff88ff', '#88ffaa',
      ];

      for (let i = 0; i < finalCount; i++) {
        const layerIndex = Math.floor(Math.random() * 4);
        const size = Math.random() * (layerIndex === 3 ? 3 : layerIndex === 2 ? 2 : 1.2) + 0.4;
        const color = starColors[Math.floor(Math.random() * starColors.length)];
        const isGiant = Math.random() > 0.95;
        const isPulsating = Math.random() > 0.85;
        const hasRays = isGiant && !mobile && Math.random() > 0.7;
        
        layers[layerIndex].push({
          id: i,
          size: isGiant ? size * 2.5 : size,
          left: Math.random() * 100 + '%',
          top: Math.random() * 100 + '%',
          color,
          opacity: Math.random() * 0.4 + 0.5,
          duration: isPulsating ? Math.random() * 2 + 1 : Math.random() * 10 + 8,
          delay: Math.random() * 5,
          isPulsating,
          isGiant,
          hasRays,
        });
      }
      setStarLayers(layers);

      const dustCount = mobile ? 10 : 120;
      const dust = [...Array(dustCount)].map((_, i) => ({
        id: `dust-${i}`,
        left: Math.random() * 100 + '%',
        top: Math.random() * 100 + '%',
        size: Math.random() * 3 + 1,
        opacity: Math.random() * 0.15 + 0.05,
        duration: Math.random() * 60 + 40,
        delay: Math.random() * 10,
        color: ['#ffffff', '#aaccff', '#ffddcc', '#ff88ff'][Math.floor(Math.random() * 4)],
        driftX: (Math.random() - 0.5) * 100,
        driftY: (Math.random() - 0.5) * 100,
      }));
      setCosmicDust(dust);

      const clusterCount = mobile ? 1 : 6;
      const clusters = [...Array(clusterCount)].map((_, i) => ({
        id: `cluster-${i}`,
        left: Math.random() * 80 + 10 + '%',
        top: Math.random() * 80 + 10 + '%',
        size: 60 + Math.random() * 100,
        stars: mobile ? 5 : 20,
        color: ['#8b5cf6', '#3b82f6', '#ec4899', '#22d3ee'][i % 4],
        rotation: Math.random() * 360,
        duration: 300 + Math.random() * 200,
      }));
      setStarClusters(clusters);
    }, [count]);


  const galaxyArms = useMemo(() => [
    { rotate: 0, color1: 'rgba(139, 92, 246, 0.05)', color2: 'rgba(59, 130, 246, 0.03)', duration: 400 },
