import React, { useEffect, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface Particle {
  id: number;
  x: number;
  y: number;
  size: number;
  color: string;
  life: number;
}

export const StardustCursor: React.FC = () => {
  const [particles, setParticles] = useState<Particle[]>([]);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    setIsMobile('ontouchstart' in window || window.innerWidth < 768);
  }, []);

  const colors = [
    'hsl(var(--electric-blue))',
    'hsl(var(--cosmic-orange))',
    '#ffffff',
    '#b3d9ff',
    '#ffe6cc'
  ];

  const addParticle = useCallback((x: number, y: number) => {
    const id = Date.now() + Math.random();
    const newParticle: Particle = {
      id,
      x,
      y,
      size: Math.random() * 4 + 1,
      color: colors[Math.floor(Math.random() * colors.length)],
      life: 1,
    };
    setParticles((prev) => [...prev.slice(-20), newParticle]);
  }, [colors]);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({ x: e.clientX, y: e.clientY });
      addParticle(e.clientX, e.clientY);
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, [addParticle]);

  useEffect(() => {
    if (isMobile) return;
    const interval = setInterval(() => {
      setParticles((prev) =>
        prev
          .map((p) => ({ ...p, life: p.life - 0.05 }))
          .filter((p) => p.life > 0)
      );
    }, 50);
    return () => clearInterval(interval);
  }, [isMobile]);

  if (isMobile) return null;

  return (
    <div className="fixed inset-0 pointer-events-none z-[9999] overflow-hidden">
      <AnimatePresence>
        {particles.map((p) => (
          <motion.div
            key={p.id}
            initial={{ opacity: 0.8, scale: 1 }}
            animate={{ 
              opacity: 0, 
              scale: 0,
              x: p.x + (Math.random() - 0.5) * 20,
              y: p.y + (Math.random() - 0.5) * 20
            }}
            exit={{ opacity: 0 }}
            className="absolute rounded-full blur-[1px]"
            style={{
              left: p.x,
              top: p.y,
              width: p.size,
              height: p.size,
              backgroundColor: p.color,
              boxShadow: `0 0 10px ${p.color}`,
              transform: 'translate(-50%, -50%)',
            }}
          />
        ))}
      </AnimatePresence>
      
      {/* Subtle core cursor glow */}
      <motion.div
        className="absolute w-8 h-8 rounded-full blur-xl pointer-events-none"
        animate={{
          left: mousePos.x,
          top: mousePos.y,
          transition: { type: 'spring', damping: 20, stiffness: 250, mass: 0.5 }
        }}
        style={{
          backgroundColor: 'hsl(var(--electric-blue) / 0.3)',
          transform: 'translate(-50%, -50%)',
        }}
      />
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface WarpSpeedProps {
  active: boolean;
  onComplete?: () => void;
}

export const WarpSpeed: React.FC<WarpSpeedProps> = ({ active, onComplete }) => {
  const [show, setShow] = useState(false);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (active) {
      setShow(true);
      const timer = setTimeout(() => {
        setShow(false);
        onComplete?.();
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [active, onComplete]);

  const [linesData, setLinesData] = useState<any[]>([]);

  useEffect(() => {
    setMounted(true);
    const newLines = Array.from({ length: 100 }).map((_, i) => {
      const angle = (i / 100) * Math.PI * 2;
      return {
        angle,
        x: Math.cos(angle) * 100,
        y: Math.sin(angle) * 100,
        delay: Math.random() * 0.5,
        isBlue: i % 3 === 0,
      };
    });
    setLinesData(newLines);
  }, []);

  useEffect(() => {
    if (active) {
      setShow(true);
      const timer = setTimeout(() => {
        setShow(false);
        onComplete?.();
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [active, onComplete]);

  return (
    <AnimatePresence>
      {show && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[10000] bg-black overflow-hidden pointer-events-none"
        >
          <div className="absolute inset-0 flex items-center justify-center">
            {mounted && linesData.map((line, i) => (
              <motion.div
                key={i}
                initial={{ 
                  scaleX: 0,
                  x: 0,
                  y: 0,
                  opacity: 0 
                }}
                animate={{ 
                  scaleX: [0, 15, 30],
                  x: [0, line.x * 15],
                  y: [0, line.y * 15],
                  opacity: [0, 1, 0]
                }}
                transition={{ 
                  duration: 1.5,
                  ease: "easeIn",
                  delay: line.delay
                }}
                className="absolute h-[2px] bg-white rounded-full origin-left"
                style={{
                  width: '20px',
                  rotate: `${(line.angle * 180) / Math.PI}deg`,
                  backgroundColor: line.isBlue ? 'hsl(var(--electric-blue))' : 'white',
                  boxShadow: line.isBlue ? '0 0 15px hsl(var(--electric-blue))' : '0 0 10px white',
                }}
              />
            ))}
          </div>
          
          <motion.div
            initial={{ scale: 0.5, opacity: 0 }}
            animate={{ scale: 4, opacity: [0, 1, 0] }}
            transition={{ duration: 1.5, ease: "easeIn" }}
            className="absolute inset-0 bg-gradient-radial from-white to-transparent opacity-20"
          />
        </motion.div>
      )}
    </AnimatePresence>
  );
};

